<?php
if ( ! defined( 'ABSPATH' ) ) exit;

// 1. 【核心修复】：类名必须与文件名和模块注册逻辑严丝合缝匹配
class YFJ_Module_Bazi_zwlpan extends YFJ_Base_Module {

    public function __construct() {
        $this->module_id = 'bazi_zwlpan';
        $this->shortcode = 'yfj_bazi_zwlpan';
        // 初始表单提交的 API 端点
        $this->api_endpoint = '/v1/Liupan/zwlpan';

        parent::__construct();

        // 2. 【核心新增】：注册紫微流盘“按需穿透加载”的专属 AJAX 钩子
        add_action('wp_ajax_yfj_ajax_get_zwlpan', [$this, 'ajax_handle_zwlpan']);
        add_action('wp_ajax_nopriv_yfj_ajax_get_zwlpan', [$this, 'ajax_handle_zwlpan']);
    }

    /**
     * 专属数据拦截与加工引擎 (初次加载盘面)
     */
    protected function process_api_data($raw_data) {
        if (is_array($raw_data)) {
            if (!isset($raw_data['base_info']['minggong'])) {
                $raw_data['base_info']['minggong'] = '未知';
            }
        }
        return $raw_data;
    }

    /**
     * 【中枢逻辑】：处理紫微流盘（流年、流月、流日、流时）的异步请求
     */
    public function ajax_handle_zwlpan() {
        // 安全校验
        check_ajax_referer('yfj_nonce', 'nonce');

        // 紫微流盘层级更深，频率更高，乘数为 10
        $this->check_rate_limit('zwlpan', 10);

        // 检查当前环境
        $env = get_option('yfj_environment', 'sandbox');

        if ($env === 'sandbox') {
            // 沙盒模式返回模拟数据
            $data = $this->get_demo_dynamic_data($_POST);
            wp_send_json_success($data);
        } else {
            // Live 模式向缘份居官方发起真实请求
            $api_key = get_option('yfj_api_key');
            if (empty($api_key)) { wp_send_json_error('API Key 未配置或已失效'); }

            $lang = get_option('yfj_language', 'zh-cn');

            // 严格映射前端传来的所有字段，包含基础八字和紫微特有参数
            $request_data = [
                'api_key'    => $api_key,
                'name'       => sanitize_text_field($_POST['name'] ?? ''),
                'sex'        => intval($_POST['sex'] ?? 0),
                'type'       => intval($_POST['type'] ?? 1),
                'year'       => intval($_POST['year'] ?? 0),
                'month'      => intval($_POST['month'] ?? 0),
                'day'        => intval($_POST['day'] ?? 0),
                'hours'      => intval($_POST['hours'] ?? 0),
                'minute'     => intval($_POST['minute'] ?? 0),
                'sect'       => intval($_POST['sect'] ?? 2),
                'zhen'       => intval($_POST['zhen'] ?? 2),
                'province'   => sanitize_text_field($_POST['province'] ?? ''),
                'city'       => sanitize_text_field($_POST['city'] ?? ''),
                'longitude'  => floatval($_POST['longitude'] ?? 0),
                'latitude'   => floatval($_POST['latitude'] ?? 0),

                // 紫微斗数流盘专属参数
                'pan_model'  => intval($_POST['pan_model'] ?? 0),
                'liu_time'   => sanitize_text_field($_POST['liu_time'] ?? ''),
                'leap_bound' => intval($_POST['leap_bound'] ?? 0),
                'pros_cons'  => intval($_POST['pros_cons'] ?? 2),
                'dx_model'   => intval($_POST['dx_model'] ?? 1),

                'lang'       => $lang,
                'iszip'      => 2
            ];

            $response = wp_remote_post('https://api.yuanfenju.com/index.php/v1/Liupan/zwlpan', [
                'body'    => $request_data,
                'timeout' => 15
            ]);

            if (is_wp_error($response)) { wp_send_json_error('接口网络连接超时'); }

            $body = json_decode(wp_remote_retrieve_body($response), true);
            if (isset($body['errcode']) && $body['errcode'] == 0) {
                wp_send_json_success($body['data']);
            } else {
                wp_send_json_error($body['errmsg'] ?? '获取紫微流盘数据失败');
            }
        }
    }

